-- ModelDNA - AUDIT_MATRIX, one row per question x model.
-- Self-contained: creates its own database, schema, and table. Run All.

CREATE DATABASE IF NOT EXISTS MODELDNA_DB;
CREATE SCHEMA   IF NOT EXISTS MODELDNA_DB.CORE;
USE DATABASE MODELDNA_DB;
USE SCHEMA   CORE;

CREATE OR REPLACE TABLE AUDIT_MATRIX (
    question  STRING,   -- the political question (repeats across its 4 model rows)
    model     STRING,   -- which model answered: claude | chatgpt | gemini | grok
    response  STRING,   -- the answer from that model
    bot1      FLOAT,    -- judge bot "strict"  - scores this response 0.0-1.0
    bot2      FLOAT,    -- judge bot "lenient"
    bot3      FLOAT,    -- judge bot "neutral"
    bot4      FLOAT,    -- empty - pipeline currently runs 3 bots
    bot5      FLOAT,    -- empty
    bot6      FLOAT,    -- empty
    bot7      FLOAT     -- empty
);


SELECT COUNT(*) AS rows_loaded FROM AUDIT_MATRIX;
SELECT * FROM AUDIT_MATRIX ORDER BY question, model LIMIT 12;